import asyncio
import websockets
import json
from collections import defaultdict
from uuid import uuid4

class Player:
    def __init__(self, username):
        self.username = username
        self.inventory = {}
        self.websocket = None

    def add_item(self, item_id, quantity):
        if item_id in self.inventory:
            self.inventory[item_id] += quantity
        else:
            self.inventory[item_id] = quantity

    def remove_item(self, item_id, quantity):
        if item_id in self.inventory and self.inventory[item_id] >= quantity:
            self.inventory[item_id] -= quantity
            if self.inventory[item_id] == 0:
                del self.inventory[item_id]
            return True
        return False

class GameServer:
    def __init__(self):
        self.players = {}
        self.lock = asyncio.Lock()

    async def register(self, websocket, username):
        async with self.lock:
            player = Player(username)
            player.websocket = websocket
            self.players[username] = player

    async def unregister(self, username):
        async with self.lock:
            if username in self.players:
                del self.players[username]

    async def handle_trade(self, sender_username, receiver_username, item_id, quantity):
        async with self.lock:
            sender = self.players.get(sender_username)
            receiver = self.players.get(receiver_username)

            if sender and receiver and sender.remove_item(item_id, quantity):
                receiver.add_item(item_id, quantity)
                await self.send_message(receiver.websocket, {"action": "item_received", "item_id": item_id, "quantity": quantity})
                return True
            return False

    async def send_message(self, websocket, message):
        await websocket.send(json.dumps(message))

    async def handler(self, websocket, path):
        username = None
        try:
            async for message in websocket:
                data = json.loads(message)
                action = data.get("action")

                if action == "register":
                    username = data.get("username")
                    await self.register(websocket, username)
                elif action == "trade":
                    receiver_username = data.get("receiver")
                    item_id = data.get("item_id")
                    quantity = data.get("quantity")
                    if await self.handle_trade(username, receiver_username, item_id, quantity):
                        await self.send_message(websocket, {"action": "trade_success"})
                    else:
                        await self.send_message(websocket, {"action": "trade_failed"})
        finally:
            if username:
                await self.unregister(username)

async def main():
    server = GameServer()
    async with websockets.serve(server.handler, "localhost", 6789):
        await asyncio.Future()  # run forever

if __name__ == "__main__":
    asyncio.run(main())